static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00355CustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const auto &dims = x_shape->GetOriginShape().GetDims();
    uint32_t N = static_cast<uint32_t>(dims[0]);
    uint32_t C = static_cast<uint32_t>(dims[1]);
    uint32_t H = static_cast<uint32_t>(dims[2]);
    uint32_t W = static_cast<uint32_t>(dims[3]);

    uint32_t totalElements = N * C * H * W;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    float momentum = (attrs != nullptr) ? attrs->GetAttrPointer<float>(0)[0] : 0.1f;
    float eps = (attrs != nullptr) ? attrs->GetAttrPointer<float>(1)[0] : 1e-5f;
    uint32_t training = (attrs != nullptr) ? static_cast<uint32_t>(attrs->GetAttrPointer<bool>(2)[0]) : 0;

    // tileLen: simple approach – use a modest tile size
    uint32_t maxTile = UB_BUDGET_BYTES / (sizeof(float) * 1); // minimal per-element compute
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = HARD_CAP_ELEMS;

    uint32_t tileLen = maxTile;
    if (totalElements < tileLen) {
        uint32_t aligned = AlignDown(totalElements, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalElements;
    }
    if (tileLen == 0) tileLen = totalElements;

    uint32_t numTiles = CeilDiv(totalElements, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalElements(totalElements);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_N(N);
    tiling.set_C(C);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_momentum(momentum);
    tiling.set_eps(eps);
    tiling.set_training(training);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
